import React, { useState, useCallback } from 'react';
import {
  View,
  Text,
  ScrollView,
  FlatList,
  SectionList,
  ActivityIndicator,
  RefreshControl,
  StyleSheet,
  SafeAreaView
} from 'react-native';

// MARK: - ScrollView (for small/fixed content)
const ScrollViewExample = () => {
  return (
    <ScrollView
      showsVerticalScrollIndicator={false}
      contentContainerStyle={styles.scrollContent}
      // Horizontal scrolling
      // horizontal={true}
      // pagingEnabled={true}
    >
      {Array.from({ length: 20 }).map((_, index) => (
        <View key={index} style={styles.scrollItem}>
          <Text>Item {index + 1}</Text>
        </View>
      ))}
    </ScrollView>
  );
};

// MARK: - FlatList (for large, dynamic lists)
const FlatListExample = () => {
  const [data, setData] = useState(
    Array.from({ length: 100 }).map((_, i) => ({ id: i.toString(), title: `Item ${i + 1}` }))
  );
  const [refreshing, setRefreshing] = useState(false);
  const [loadingMore, setLoadingMore] = useState(false);

  // Pull to refresh
  const onRefresh = useCallback(() => {
    setRefreshing(true);
    setTimeout(() => {
      setData(Array.from({ length: 100 }).map((_, i) => ({ id: i.toString(), title: `Refreshed ${i + 1}` })));
      setRefreshing(false);
    }, 1500);
  }, []);

  // Infinite scroll (pagination)
  const loadMore = useCallback(() => {
    if (loadingMore) return;
    setLoadingMore(true);
    setTimeout(() => {
      const newItems = Array.from({ length: 20 }).map((_, i) => ({
        id: (data.length + i).toString(),
        title: `Item ${data.length + i + 1}`
      }));
      setData(prev => [...prev, ...newItems]);
      setLoadingMore(false);
    }, 1000);
  }, [data.length, loadingMore]);

  const renderItem = useCallback(({ item, index }) => (
    <View style={styles.listItem}>
      <Text style={styles.itemIndex}>{index + 1}</Text>
      <Text style={styles.itemTitle}>{item.title}</Text>
    </View>
  ), []);

  const renderFooter = () => {
    if (!loadingMore) return null;
    return (
      <View style={styles.footerLoader}>
        <ActivityIndicator size="small" />
        <Text style={styles.footerText}>Loading more...</Text>
      </View>
    );
  };

  return (
    <SafeAreaView style={styles.safeArea}>
      <FlatList
        data={data}
        renderItem={renderItem}
        keyExtractor={item => item.id}
        // Performance optimizations
        initialNumToRender={10}
        maxToRenderPerBatch={10}
        windowSize={21}
        removeClippedSubviews={true}
        // Pull to refresh
        refreshControl={
          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} />
        }
        // Infinite scroll
        onEndReached={loadMore}
        onEndReachedThreshold={0.5}
        ListFooterComponent={renderFooter}
        // Empty state
        ListEmptyComponent={
          <View style={styles.emptyState}>
            <Text>No items found</Text>
          </View>
        }
        // Optimize for item updates
        extraData={data.length}
      />
    </SafeAreaView>
  );
};

